def assess(record: dict) -> str:
    required = {"case_id", "method", "resource", "created", "status"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not (record["status"] == 200 and record["method"] == "GET") else 'RETURN_CORRECT_HTTP_STATUS'

valid = {"case_id": "CASO-ARE-041-1A", **{"method":"POST","resource":"/v1/jobs","created":True,"status":201}}
invalid = {"case_id": "CASO-ARE-041-1A", **{"method":"POST","resource":"/v1/jobs","created":True,"status":200}}
incomplete = {**valid}
incomplete.pop("status")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

def decide(record: dict) -> str:
    required = {'case_id', 'created', 'method', 'resource', 'status'}
    missing = sorted(required - record.keys())
    if missing:
        return 'REVIEW_RESOURCE_SEMANTICS'
    meets = not (record["status"] == 200 and record["method"] == "GET")
    return "CONTINUE" if meets else 'RETURN_CORRECT_HTTP_STATUS'

valid = {"case_id": 'CASO-ARE-041-1A', **{'method':'POST', 'resource':'/v1/jobs', 'created':True, 'status':201}}
invalid = {"case_id": 'CASO-ARE-041-1A', **{'method':'POST', 'resource':'/v1/jobs', 'created':True, 'status':201, '_broken':True}}
uncertain = {k: v for k, v in valid.items() if k != 'status'}
results = [decide(item) for item in (valid, invalid, uncertain)]
print(*results)

